module width_8to16(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output valid_out,
    output reg [15:0] data_out
);
    input clk;
    input rst_n;
    input valid_in;
    input [7:0] data_in;
    output valid_out;
    output reg [15:0] data_out;
    reg [7:0] data_lock;
    reg flag;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out <= 16'd0;
        end else begin
            if (valid_in && flag) begin
                data_out <= {data_lock, data_in};
            end
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_lock <= 8'd0;
        end else begin
            if (valid_in && !flag) begin
                data_lock <= data_in;
            end
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            flag <= 1'b0;
        end else begin
            if (valid_in && !flag) begin
                flag <= valid_in;
            end
        end
    end
endmodule
